test_cases.python_test_script:
def test_tc_gw_ign_001_present(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs, 'GW_IgnitionStatus not detected'

def test_tc_gw_ign_002_off(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_ignition_state(msg.data) == 0

def test_tc_gw_ign_003_acc(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_ignition_state(msg.data) == 1

def test_tc_gw_ign_004_on(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_ignition_state(msg.data) == 2

def test_tc_gw_ign_005_start(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_ignition_state(msg.data) == 3

def test_tc_gw_ign_006_periodic(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert len(msgs) >= 3

def test_tc_gw_ign_007_no_change(can_bus):
    msgs = collect_gw_messages(can_bus, 3.0)
    assert msgs
    first = get_ignition_state(msgs[0].data)
    for msg in msgs:
        assert get_ignition_state(msg.data) == first

def test_tc_gw_ign_008_dlc(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_IGNITION_STATUS_DLC
